import{_ as e,c as r,o as a,U as t}from"./chunks/framework.9QHaLlVJ.js";const _=JSON.parse('{"title":"Aggregated API Server","description":"","frontmatter":{},"headers":[],"relativePath":"doc/DevOps/Kubernetes/基础/aggregated-api-server.md","filePath":"packages/doc/src/DevOps/Kubernetes/基础/aggregated-api-server.md","lastUpdated":1705214817000}'),s={name:"doc/DevOps/Kubernetes/基础/aggregated-api-server.md"},o=t('<h1 id="aggregated-api-server" tabindex="-1">Aggregated API Server <a class="header-anchor" href="#aggregated-api-server" aria-label="Permalink to &quot;Aggregated API Server&quot;">​</a></h1><p>Aggregated（聚合的）API server 是为了将原来的 API server 这个巨石（monolithic）应用给拆分成，为了方便用户开发自己的 API server 集成进来，而不用直接修改 kubernetes 官方仓库的代码，这样一来也能将 API server 解耦，方便用户使用实验特性。这些 API server 可以跟 core API server 无缝衔接，使用 kubectl 也可以管理它们。</p><h2 id="架构" tabindex="-1">架构 <a class="header-anchor" href="#架构" aria-label="Permalink to &quot;架构&quot;">​</a></h2><p>我们需要创建一个新的组件，名为 <code>kube-aggregator</code>，它需要负责以下几件事：</p><ul><li>提供用于注册 API server 的 API</li><li>汇总所有的 API server 信息</li><li>代理所有的客户端到 API server 的请求</li></ul><p><strong>注意</strong>：这里说的 API server 是一组 “API Server”，而不是说我们安装集群时候的那个 API server，而且这组 API server 是可以横向扩展的。</p><h2 id="安装配置聚合的-api-server" tabindex="-1">安装配置聚合的 API server <a class="header-anchor" href="#安装配置聚合的-api-server" aria-label="Permalink to &quot;安装配置聚合的 API server&quot;">​</a></h2><p>有两种方式来启用 <code>kube-aggregator</code>：</p><ul><li>使用 <strong>test mode/single-user mode</strong>，作为一个独立的进程来运行</li><li>使用 <strong>gateway mode</strong>，<code>kube-apiserver</code> 将嵌入到 <code>kbe-aggregator</code> 组件中，它将作为一个集群的 gateway，用来聚合所有 apiserver。</li></ul><p><code>kube-aggregator</code> 二进制文件已经包含在 Kubernetes release 里面了。</p>',10),g=[o];function d(i,c,l,n,p,v){return a(),r("div",null,g)}const u=e(s,[["render",d]]);export{_ as __pageData,u as default};
